function populate(card, data) {
  const id = card.dataset.id;
  const extra = extraData[id] || { dieta: "Desconocido", estado: "No evaluado" };
  
  modalImg.src = card.querySelector('img').src;
  modalImg.alt = data.nombre;
  modalBadge.textContent = data.lugar;
  modalImgNum.textContent = String(tarjetasVisibles.indexOf(card) + 1).padStart(2, '0');
  modalScientific.textContent = data.cientifico;
  modalTitle.textContent = data.nombre;
  modalLocation.textContent = data.lugar;
  
  const mdDiet = document.getElementById('modalDiet');
  if(mdDiet) mdDiet.textContent = extra.dieta;
  const mdCons = document.getElementById('modalConservation');
  if(mdCons) mdCons.textContent = extra.estado;
  
  modalHistory.textContent = data.historia;
  modalFact.textContent = data.curiosidad;
  modalIndicator.textContent = (currentIdx + 1) + ' / ' + tarjetasVisibles.length;
  document.querySelector('.modal-content-panel').scrollTop = 0;
}

function closeModal() {
  overlay.classList.remove('active');
  document.body.style.overflow = '';
}

document.querySelectorAll('.animal-card').forEach(c => c.addEventListener('click', () => openModal(c)));
document.getElementById('modalClose').addEventListener('click', closeModal);
overlay.addEventListener('click', e => { if (e.target === overlay) closeModal() });

document.addEventListener('keydown', e => {
  if (!overlay.classList.contains('active')) return;
  if (e.key === 'Escape') closeModal();
  if (e.key === 'ArrowRight') document.getElementById('modalNext').click();
  if (e.key === 'ArrowLeft') document.getElementById('modalPrev').click();
});

document.getElementById('modalNext').addEventListener('click', () => {
  currentIdx = (currentIdx + 1) % tarjetasVisibles.length;
  populate(tarjetasVisibles[currentIdx], faunaDB[tarjetasVisibles[currentIdx].dataset.id]);
});
document.getElementById('modalPrev').addEventListener('click', () => {
  currentIdx = (currentIdx - 1 + tarjetasVisibles.length) % tarjetasVisibles.length;
  populate(tarjetasVisibles[currentIdx], faunaDB[tarjetasVisibles[currentIdx].dataset.id]);
});

// Swipe en móviles para cambiar imagen
let touchStartX = 0;
document.getElementById('modalShell').addEventListener('touchstart', e => {
  touchStartX = e.changedTouches[0].clientX;
}, { passive: true });

document.getElementById('modalShell').addEventListener('touchend', e => {
  const dx = e.changedTouches[0].clientX - touchStartX;
  if (Math.abs(dx) > 50) {
    if (dx < 0) document.getElementById('modalNext').click();
    else document.getElementById('modalPrev').click();
  }
});